export type SAFEXValueType = boolean | number;

/**
 * Provides access to http://go/safex flags from the frontend. Note that this is a temporary
 * workaround until direct `safex` imports are available.
 *
 * When the full webapp is loaded, delegates to `window.__debug__safex` which is set by
 * `@databricks/web-shared` and includes full RPC-based flag resolution + local overrides.
 * Falls back to `__TEST_FLAG_OVERRIDES__` for test environments.
 *
 * @param flag The name of the flag to check
 * @param defaultValue The default value to return if the flag is not set
 * @returns
 */
export const safex: <T extends SAFEXValueType>(flag: string, defaultValue: T) => T = <T>(
  flag: string,
  defaultValue: T,
) => {
  // Catching errors here, because we don't have type-safety to ensure
  // that `__debug__safex`'s API hasn't changed.
  try {
    const globalSafex = (window as any).__debug__safex;
    if (globalSafex) {
      return globalSafex(flag, defaultValue);
    }
    const override = (globalThis as any).__TEST_FLAG_OVERRIDES__?.[flag];
    if (override !== undefined) {
      return override;
    }
    return defaultValue;
  } catch (e) {
    return defaultValue;
  }
};

/**
 * Reads a server-side feature flag value. Delegates to `window.__debug__serverSideSafe`
 * which is set by `@databricks/web-shared` and includes full flag resolution with
 * local overrides (localStorage + URL params) in dev/staging.
 * Falls back to `__DATABRICKS_SAFE_FLAGS__` and `__TEST_FLAG_OVERRIDES__` when the
 * full webapp implementation is not available.
 *
 * @param flag The name of the flag to check
 * @param defaultValue The default value to return if the flag is not set
 * @returns
 */
export const serverSideSafe: <T extends SAFEXValueType>(flag: string, defaultValue: T) => T = <T>(
  flag: string,
  defaultValue: T,
) => {
  try {
    // Delegate to web-shared's serverSideSafe if available (includes local overrides)
    const globalServerSideSafe = (window as any).__debug__serverSideSafe;
    if (globalServerSideSafe) {
      return globalServerSideSafe(flag, defaultValue);
    }
    // Fallback: check server-side flags directly
    const explicitOverride = (window as any).__DATABRICKS_SAFE_FLAGS__?.[flag];
    if (explicitOverride !== undefined) {
      return explicitOverride;
    }
    const envOverride = (globalThis as any).__TEST_FLAG_OVERRIDES__?.[flag];
    if (envOverride !== undefined) {
      return envOverride;
    }
    return defaultValue;
  } catch (e) {
    return defaultValue;
  }
};
