type AnyFunction = (...args: any[]) => any;

export interface ImplicitContextValue {
  wrap: <T extends AnyFunction>(callback: T) => T;
  wrapNoProxy: <T extends AnyFunction>(callback: T) => T;
}

export type ImplicitContextGetter = () => ImplicitContextValue;

const identityWrap: ImplicitContextValue['wrap'] = (callback) => callback;

const defaultImplicitContext: ImplicitContextValue = {
  wrap: identityWrap,
  wrapNoProxy: identityWrap,
};

const defaultImplicitContextGetter: ImplicitContextGetter = () => defaultImplicitContext;

let implicitContextGetter = defaultImplicitContextGetter;

// Design-system cannot import web-shared directly, so webapp/web-shared installs
// a getter once and LegacyForm resolves the current implicit context at render time.
export function setImplicitContextGetter(getter: ImplicitContextGetter) {
  implicitContextGetter = getter;
}

export function getImplicitContext() {
  return implicitContextGetter();
}

export function resetImplicitContextGetterForTests() {
  implicitContextGetter = defaultImplicitContextGetter;
}
